; ラドミラの塔

name = ラドミラの塔14Ｆ
insideName = 14Ｆ
upper = ラドミラの塔15Ｆ
lower = ラドミラの塔13Ｆ
level = 62
bgm = tower
margin = 3
shadow = dark
sky = dawnforest
roof = stone
antiWarp = true

; パーツ画像
━ = stone_h
✜ = stone_h
… = half
　 = marble
／ = door
┯ = button
㊦ = ladderd

; 敵情報
monsters = マンイーター,怒りの霊魂,サイクロプス,ゴールドマン,ケイブジャイアント

; 移動ポイント
(A) = x:2, y:3
(B) = x:1, y:7
(C) = x:6, y:7
(D) = x:8, y:3
(E) = x:7, y:1
(F) = x:4, y:7
(G) = x:7, y:6
(H) = x:2, y:6

; 宝箱
box[1] = 罠はない,スライムの彫像

[map]
;---------------------------------------------------------------------------------------------------------------
;    0   1   2   3   4   5   6   7   8  
  		┏━━┯━━━━━━━━━┯┳┯┓
 8		┃Ⓒ　③　　　　　Ⓐ　　　③┃①┃
  		┣………┓　┏……　┏……　┣／┫
 7		┃　　㊦￤　￤　　　￤　　　￤②┨
  		┃　┏…┫　┗…┓　￤　┏…┛　┃
 6		┃　￤　￤　　Ⓔ￤　￤　￤　　　┃
  		┃　￤　┗…┓　￤　￤　￤　……┫
 5		┃Ⓐ￤❶　Ⓖ￤　￤　￤　￤Ⓒ　　┃
  		┃　┣………┛　￤　￤　┣…┓　┃
 4		┃　￤　　　　Ⓖ　　　Ⓓ￤　￤　┃
  		┃　┣…┓　┏……………┛　￤　┃
 3		┠③￤　￤　￤Ⓕ　　　Ⓗ　　✜　┃
  		┣…┛　￤　￤　￤　…………┻━┫
 2		┃　　　　Ⓑ￤　￤Ⓓ　　　　　③┨
  		┃　…………┫　┗…………………┫
 1		┃　　　　③￤　　　　　　　　③┨
